script.text:

function load$&Identity;$(g) {
  g._$k = [];
  g._$d = [];
  g._$i = g._getColumnOrder('stt_rec');
  g._$j = g._getColumnOrder('ngay_ct');
  g._$t = g._getColumnOrder('tag');
  g._$f = 'keys';
  g.add_commandEvent(on$&Identity;$ExecuteCommand);
}
function dispose$&Identity;$(g) {
  g._$k = g._$i = g._$t = g._$f = g._$d = g._$j = null;
  try {g.remove_commandEvent(on$&Identity;$ExecuteCommand);} catch (ex) {}
}
function scatter$&Identity;$(g){
  fill$Grid(g, true);
  if (g._rowCount > 0) {
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
	}
}
function on$&Identity;$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'CreateWriteOff':
      if (isCheck$Grid(g)) g.showForm('WPAdvancedWriteOffCreate');
        else e.type.cancelEvent = true;
      break;
    default:
      break;
  }
}

      &JavascriptReportInit;

function toggle$&Identity;$Grid(o) {
  var c = o.parentNode.parentNode.parentNode.id, g = $find($func.left(c, c.length - 11));
  for (var r = 1; r <= g._rowCount; r++) {
    var k = row$Key(g, r), i = Array.indexOf(g._$k, k);
    if (i == -1) {
      Array.add(g._$k, k);
      Array.add(g._$d, g._getItemValue(r, g._$j));
    } else {
      Array.removeAt(g._$k, i);
      Array.removeAt(g._$d, i);
    }
    g._setItemValue(r, g._$t, (i == -1));
  }
  g._focusWhenTabChanged();
}
function on$&Identity;$Change$SelectedValue(o) {
  var r = $func.getLocationCell(o)[0], g = $find(o.id.split('_inputCell_')[0]), k = row$Key(g, r), i = Array.indexOf(g._$k, k);
  if (i == -1) {
    Array.add(g._$k, k);
    Array.add(g._$d, g._getItemValue(r, g._$j));
  } else {
    Array.removeAt(g._$k, i);
    Array.removeAt(g._$d, i);
  }
}

/* <flatten type="Javascript"> */
function isCheck$Grid(g) {
  var msg = (g._language == 'v' ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  if (g._$k.length == 0) {
    $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    return false;
  }
  return true;
}
function fill$Grid(g, f) {
  if (f && g._$k.length == 0) return;
  for (var r = 1; r <= g._rowCount; r++) {
    var k = row$Key(g, r), i = Array.indexOf(g._$k, k);
    g._setItemValue(r, g._$t, (i > -1));
  }
}
function row$Key(g, r) {return g._getItemValue(r, g._$i);}
/* </flatten> */
